html:
{% set _ca_list = frappe.get_all('CA Company Tax Config', filters={'company': doc.company}, pluck='name', limit=1) %}{% set ca = frappe.get_doc('CA Company Tax Config', _ca_list[0]) if _ca_list else none %}
<style>
.inv-header{display:flex;justify-content:space-between;margin-bottom:20px}
.inv-table{width:100%;border-collapse:collapse;margin:16px 0}
.inv-table th{background:#f4f4f4;text-align:left;padding:6px 8px;border:1px solid #ddd;font-size:11px}
.inv-table td{padding:6px 8px;border:1px solid #ddd;font-size:11px}
.totals{text-align:right;margin-top:8px}
.totals table{margin-left:auto}
.totals td{padding:3px 8px;font-size:11px}
.grand-total td{font-weight:bold;font-size:13px;border-top:2px solid #333}
.ca-reg{margin-top:24px;padding-top:10px;border-top:1px solid #ccc;font-size:10px;color:#555}
</style>

<div class='inv-header'>
  <div>
    <strong style='font-size:16px'>{{ doc.company }}</strong><br>
    {% if doc.company_address %}{% set a=frappe.get_doc('Address',doc.company_address) %}{{ a.address_line1 }}, {{ a.city }}, {{ a.state }} {{ a.pincode }}{% endif %}
  </div>
  <div style='text-align:right'>
    <strong>INVOICE</strong><br><strong>{{ doc.name }}</strong><br>
    Date: {{ doc.posting_date }}<br>
    {% if doc.due_date %}Due: {{ doc.due_date }}{% endif %}
  </div>
</div>

<div style='margin-bottom:16px'>
  <strong>Bill To:</strong><br>{{ doc.customer }}<br>
  {% if doc.customer_address %}{% set ca2=frappe.get_doc('Address',doc.customer_address) %}{{ ca2.address_line1 }}, {{ ca2.city }}, {{ ca2.state }} {{ ca2.pincode }}{% endif %}
</div>

<table class='inv-table'>
  <thead><tr><th>Item</th><th>Description</th><th style='text-align:right'>Qty</th><th style='text-align:right'>Rate</th><th style='text-align:right'>Amount</th></tr></thead>
  <tbody>
  {% for item in doc.items %}
  <tr>
    <td>{{ item.item_code }}</td>
    <td>{{ item.item_name }}</td>
    <td style='text-align:right'>{{ item.qty }} {{ item.uom }}</td>
    <td style='text-align:right'>{{ doc.currency }} {{ '%.2f'|format(item.rate) }}</td>
    <td style='text-align:right'>{{ doc.currency }} {{ '%.2f'|format(item.amount) }}</td>
  </tr>
  {% endfor %}
  </tbody>
</table>

<div class='totals'>
  <table>
    <tr><td>Net Total</td><td>{{ doc.currency }} {{ '%.2f'|format(doc.net_total) }}</td></tr>
    {% for tax in doc.taxes %}
    <tr><td>{{ tax.description }}</td><td>{{ doc.currency }} {{ '%.2f'|format(tax.tax_amount) }}</td></tr>
    {% endfor %}
    <tr class='grand-total'><td>Total</td><td>{{ doc.currency }} {{ '%.2f'|format(doc.grand_total) }}</td></tr>
  </table>
</div>

{% if ca and (ca.gst_registration_number or ca.qst_registration_number) %}
<div class='ca-reg'>
  {% if ca.gst_registration_number %}<span>GST/HST Registration No.: {{ ca.gst_registration_number }}</span>{% endif %}
  {% if ca.gst_registration_number and ca.qst_registration_number %}&nbsp;&nbsp;|&nbsp;&nbsp;{% endif %}
  {% if ca.qst_registration_number %}<span>QST Registration No.: {{ ca.qst_registration_number }}</span>{% endif %}
</div>
{% endif %}
